### Sauberes Programm ###
def combinations(length):
    nucleotides=['A','T','G','C']
    combs=['A','T','G','C']
    actual_length=1
    while actual_length<length:
        new_combs=[]
        for i in combs:
            for j in nucleotides:
                new_combs.append(i+j)
        combs=new_combs
        actual_length +=1
    return(combs)

def motives(DNA, motive_length):
    ammounts={}
    for comb in combinations(motive_length):
        ammounts.update({comb:0})
    for i in range(len(DNA)-4):
        motive=DNA[i:i+4]
        ammounts.update({motive:ammounts.get(motive)+1})
    return(ammounts)

def visualized_motives(DNA, motive_length):
    ammounts=motives(DNA, motive_length)
    for i in ammounts.keys():
        print(i+' '+ ammounts[i]*'-'+' '+str(ammounts[i]))

pUC4K = ''
visualized_motives(pUC4K, 4)